// Gelen ham HTML verisini alıyoruz
const html = $input.first().json.data || "";

// HTML içindeki tüm <td>...</td> hücre içeriklerini yakalıyoruz
const tdRegex = /<td>([\s\S]*?)<\/td>/gi;
const result = [];
let match;
let allCells = [];

while ((match = tdRegex.exec(html)) !== null) {
    // Hücre içindeki boşlukları ve olası HTML etiketlerini temizle
    let cellText = match[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
    if (cellText) {
        allCells.push(cellText);
    }
}

// Tabloda her satırda 2 adet <td> var: İlki Şirket Adı, ikincisi Web Sitesi (veya boş).
// Sadece 1. sütundaki şirket isimlerini döngüyle çekiyoruz.
for (let i = 0; i < allCells.length; i += 2) {
    let companyName = allCells[i];

    // Başlık satırını veya çok kısa verileri filtrele
    if (companyName && companyName.length > 2 && !companyName.includes("FİRMA ADI")) {
        result.push({
            json: {
                company_name: companyName
            }
        });
    }
}

// TEST İÇİN: Akışın tıkanmaması adına ilk aşamada sadece ilk 5 şirketi alalım.
// Her şeyin çalıştığından emin olunca alttaki satırı "return result;" yaparsın.
const startIndex = 0; // Offset index for crash recovery
    return result.slice(startIndex);

// OpenAI'dan gelen ham metni alıyoruz
const rawText = $input.first().json.output?.[0]?.content?.[0]?.text || $input.first().json.text || "";

// Başındaki ve sonundaki markdown temizliklerini yapıyoruz
let cleanText = rawText.replace(/```json/gi, "").replace(/```/g, "").trim();

let parsedData = {
    email: null,
    subject: "",
    body: ""
};

try {
    // Metni düzgün bir JSON objesine çeviriyoruz
    parsedData = JSON.parse(cleanText);
} catch (e) {
    // Eğer OpenAI bazen süslü parantezleri eksik bıraktıysa veya parse hatası olduysa manuel ayıkla
    const emailMatch = cleanText.match(/"email"\s*:\s*"([^"]+)"/);
    const subjectMatch = cleanText.match(/"subject"\s*:\s*"([^"]+)"/);
    const bodyMatch = cleanText.match(/"body"\s*:\s*"([\s\S]+?)"\s*\n*\s*}/);

    if (emailMatch) parsedData.email = emailMatch[1];
    if (subjectMatch) parsedData.subject = subjectMatch[1];
    if (bodyMatch) parsedData.body = bodyMatch[1];
}

// Döngüdeki orijinal şirket adını da kaybetmemek için Excel'e göndereceğimiz veriye ekliyoruz
const originalCompanyName = $('Loop Over Items').item.json.company_name || "";

return [{
    json: {
        company_name: originalCompanyName,
        email: parsedData.email,
        subject: parsedData.subject,
        body: parsedData.body
    }
}];
